  1	import { useMemo, useRef, useState } from 'react';
  2	import { useNavigate } from 'react-router-dom-v5-compat';
  3	import type { Interval } from 'luxon';
  4	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
  5	import { TimeRangeOptions } from 'src/overview/tabs/Overview/utils/timeRangeOptions';
  6	
  7	import { PlanModelRef } from '@kubev2v/types';
  8	import {
  9	  Chart,
 10	  ChartArea,
 11	  ChartAxis,
 12	  ChartStack,
 13	  ChartVoronoiContainer,
 14	} from '@patternfly/react-charts';
 15	import type { ChartAreaProps } from '@patternfly/react-charts/src/components/ChartArea/ChartArea';
 16	import { Button, ButtonVariant } from '@patternfly/react-core';
 17	import { TELEMETRY_EVENTS } from '@utils/analytics/constants';
 18	import { useForkliftAnalytics } from '@utils/analytics/hooks/useForkliftAnalytics';
 19	import { useForkliftTranslation } from '@utils/i18n';
 20	
 21	import useMigrationCounts from '../../hooks/useMigrationCounts';
 22	import { ChartColors } from '../../utils/colors';
 23	import { navigateToHistoryTab } from '../../utils/navigate';
 24	import type { ChartDatumWithName, MigrationDataPoint } from '../../utils/types';
 25	
 26	import { useResizeObserver } from './useResizeObserver';
 27	
 28	const MAX_DOMAIN_Y = 5;
 29	
 30	const VmMigrationsHistoryChart = ({
 31	  selectedRange,
 32	  vmMigrationsDataPoints,
 33	}: {
 34	  selectedRange: TimeRangeOptions;
 35	  vmMigrationsDataPoints: {
 36	    running: MigrationDataPoint[];
 37	    failed: MigrationDataPoint[];
 38	    succeeded: MigrationDataPoint[];
 39	  };
 40	}) => {
 41	  const { t } = useForkliftTranslation();
 42	  const { trackEvent } = useForkliftAnalytics();
 43	  const { count } = useMigrationCounts();
 44	  const chartContainerRef = useRef<HTMLDivElement>(null);
 45	  const chartDimensions = useResizeObserver(chartContainerRef);
 46	  const { failed, running, succeeded } = vmMigrationsDataPoints;
 47	  const navigate = useNavigate();
 48	  const [activeArea, setActiveArea] = useState<string | null>(null);
 49	  const [activeInterval, setActiveInterval] = useState<Interval<true> | Interval<false> | null>(
 50	    null,
 51	  );
 52	
 53	  const plansListURL = useMemo(() => {
 54	    return getResourceUrl({
 55	      namespaced: false,
 56	      reference: PlanModelRef,
 57	    });
 58	  }, []);
 59	
 60	  const maxVmMigrationValue = Math.max(
 61	    ...running.map((migration) => migration.value),
 62	    ...failed.map((migration) => migration.value),
 63	    ...succeeded.map((migration) => migration.value),
 64	  );
 65	
 66	  const legendData = [
 67	    { name: t('Running'), symbol: { fill: ChartColors.Executing } },
 68	    { name: t('Failed'), symbol: { fill: ChartColors.Failure } },
 69	    { name: t('Succeeded'), symbol: { fill: ChartColors.Success } },
 70	  ];
 71	
 72	  const maxTicks = Math.max(MAX_DOMAIN_Y, Math.ceil(maxVmMigrationValue) + 1);
 73	  const tickStep = Math.ceil(maxTicks / 6);
 74	  const tickValues = Array.from({ length: maxTicks }, (_, i) => i + 1).filter(
 75	    (val) => val === 1 || val % tickStep === 0 || val === maxTicks,
 76	  );
 77	
 78	  const mapDataPoints = (dataPoints: MigrationDataPoint[], name = ''): ChartDatumWithName[] =>
 79	    dataPoints.map(({ dateLabel, interval, migrations, value }) => ({
 80	      interval,
 81	      migrations,
 82	      name,
 83	      x: dateLabel,
 84	      y: value,
 85	    }));
 86	
 87	  const getAreaProps = (
 88	    dataPoints: MigrationDataPoint[],
 89	    areaName: string,
 90	    color: string,
 91	  ): ChartAreaProps => ({
 92	    colorScale: [color],
 93	    data: mapDataPoints(dataPoints, areaName),
 94	    events: [
 95	      {
 96	        eventHandlers: {
 97	          onClick: () => {
 98	            if (!activeInterval) return;
 99	            navigateToHistoryTab({
100	              interval: activeInterval,
101	              navigate,
102	              status: areaName,
103	            });
104	          },
105	        },
106	        target: 'data',
107	      },
108	    ],
109	    style: {
110	      data: {
111	        cursor: activeArea === areaName && activeInterval ? 'pointer' : 'default',
112	        opacity: activeArea === areaName && activeInterval ? 1 : 0.7,
113	        stroke: activeArea === areaName && activeInterval ? color : undefined,
114	        strokeWidth: activeArea === areaName && activeInterval ? 4 : 2,
115	      },
116	    },
117	  });
118	
119	  return (
120	    <div ref={chartContainerRef} className="pf-v6-u-h-100 pf-v6-u-w-100">
121	      {count.Total === 0 && (
122	        <div className="forklift-overview__create-plan-btn">
123	          <Button
124	            variant={ButtonVariant.primary}
125	            onClick={() => {
126	              trackEvent(TELEMETRY_EVENTS.PLAN_CREATE_FROM_OVERVIEW_CLICKED);
127	              navigate(`${plansListURL}/~new`);
128	            }}
129	          >
130	            {t('Create migration plan')}
131	          </Button>
132	        </div>
133	      )}
134	      <Chart
135	        ariaDesc={t('Area chart with VM migration history')}
136	        containerComponent={
137	          <ChartVoronoiContainer
138	            labels={({ datum }: { datum: ChartDatumWithName }) => {
139	              return datum.y === 0 || !datum.name
140	                ? (undefined as unknown as string)
141	                : `${t('{{count}} VM migration', { count: datum.y })} ${datum.name.toLowerCase()}`;
142	            }}
143	            constrainToVisibleArea
144	            onActivated={(points: ChartDatumWithName[]) => {
145	              const activePoint = points.find((pt) => pt.y > 0);
146	              if (!activePoint) {
147	                setActiveArea(null);
148	                setActiveInterval(null);
149	                return;
150	              }
151	              setActiveArea(activePoint.name);
152	              setActiveInterval(activePoint.interval);
153	            }}
154	          />
155	        }
156	        legendData={legendData}
157	        legendPosition="bottom"
158	        maxDomain={{ y: maxVmMigrationValue ? undefined : MAX_DOMAIN_Y }}
159	        padding={{ bottom: 55, left: 50, right: 50, top: 20 }}
160	        width={chartDimensions.width}
161	        height={chartDimensions.height}
162	      >
163	        <ChartAxis
164	          tickCount={6}
165	          tickFormat={(tick: string) => {
166	            if (selectedRange === TimeRangeOptions.Last24H) {
167	              const splits = tick.split(' ');
168	              return splits[splits.length - 1];
169	            }
170	            return tick;
171	          }}
172	        />
173	        <ChartAxis dependentAxis tickValues={tickValues} />
174	        <ChartStack>
175	          <ChartArea {...getAreaProps(failed, t('Failed'), ChartColors.Failure)} />
176	          <ChartArea {...getAreaProps(running, t('Running'), ChartColors.Executing)} />
177	          <ChartArea {...getAreaProps(succeeded, t('Succeeded'), ChartColors.Success)} />
178	        </ChartStack>
179	      </Chart>
180	    </div>
181	  );
182	};
183	
184	export default VmMigrationsHistoryChart;

